const __FIXTURES__ = [{"id":"gitea-draft-release-access-control","skill":"engineering/aegis","repo":"go-gitea/gitea","commit":"1eced4a7c099459af42412bb32a83241650c0f8f","pr":"https://github.com/go-gitea/gitea/pull/36659","language":"go","domain_tags":["broken-access-control","idor","missing-authorization","draft-visibility","owasp-a01"],"target":"before.txt","answer":"after.txt","answer_key":"fix.diff","file":"the Gitea releases REST API, EXACTLY the 2 files the commit modified, in full and uncurated: routers/api/v1/repo/release.go (421L — GetRelease/GetLatestRelease/ListReleases/CreateRelease/EditRelease/DeleteRelease) + routers/api/v1/repo/release_attachment.go (407L — the release-attachment GET/list/CRUD handlers). 832 lines total before the fix.","fix_summary":"BROKEN ACCESS CONTROL / IDOR (OWASP A01) — a missing OBJECT-LEVEL authorization check, the aegis lesson 'enforce server-side authorization on every read; a partial check is not the check'. GetRelease fetches a release with repo_model.GetReleaseForRepoByID(ctx.Repo.Repository.ID, id) and returns it after only a repo-match and an IsTag check — but it does NOT gate DRAFT (unpublished) releases, so any caller with mere repo READ access (and, on a public repo, an anonymous user) can fetch an unpublished draft release by id, plus its attachments (ListReleaseAttachments / GetReleaseAttachment via checkReleaseMatchRepo) and see drafts in ListReleases. Draft releases are unpublished content that should require WRITE access. The maintainer's fix.diff adds canAccessDraftRelease(ctx) (signed in AND CanWrite(unit.TypeReleases) AND the API token carries repo-write scope) and gates GetRelease, the attachment handlers, and the IncludeDrafts flag of ListReleases behind it. THE ATTRACTOR (why this discriminates): there IS already an access control here — the release is fetched scoped to the current repo (GetReleaseForRepoByID) and there is an IsTag 404 — so the read path LOOKS authorized; the missing nuance (a draft is a sub-resource that needs a STRONGER permission than the repo's read gate) is Gitea-specific domain knowledge a reviewer glosses over. The repo-scoped fetch is the present-but-incomplete control that misdirects, structurally like 'parameterized != authorized'. SCOPE: before.txt is the WHOLE 2 files the commit touched, full and UN-curated — the missing draft gate is determinable from context but buried in ~832 lines of idiomatic API code, NOT excerpted to point at it. DISCRIMINATION EVIDENCE (pre-validated before adoption): a blind, security-primed no-skill review of before.txt MISSED this entirely — its top finding was a speculative nil-pointer/operator-precedence DoS hazard it itself judged 'safe in that path', plus a CreateRelease logic nitpick and an attachment check it concluded was 'actually sound'; it never once reasoned about draft-release visibility. So the base arm chases a hedged distractor while leaving the real, confirmed access-control hole un-flagged. Unlike the prior kubestellar fixture (a vuln buffet where the base arm found 5+ other confirmed vulns and got capped at 8), this file is otherwise clean — the draft access-control issue is the DOMINANT confirmed security problem, so missing it should actually cost score. PROVENANCE: a real, reviewed, merged Gitea PR (#36659) authored by Lunny Xiao (Gitea's founder); Copilot is a co-author (drafting assistance only) — the project's own accepted change. The grader scores the review against fix.diff and does not see this note. Repo: go-gitea/gitea, MIT, ~56k stars.","before":"// ===== routers/api/v1/repo/release.go =====\n// Copyright 2016 The Gitea Authors. All rights reserved.\n// SPDX-License-Identifier: MIT\n\npackage repo\n\n\u0069mport (\n\t\"errors\"\n\t\"fmt\"\n\t\"net/http\"\n\n\t\"code.gitea.io/gitea/models/db\"\n\t\"code.gitea.io/gitea/models/perm\"\n\trepo_model \"code.gitea.io/gitea/models/repo\"\n\t\"code.gitea.io/gitea/models/unit\"\n\t\"code.gitea.io/gitea/modules/git\"\n\tapi \"code.gitea.io/gitea/modules/structs\"\n\t\"code.gitea.io/gitea/modules/web\"\n\t\"code.gitea.io/gitea/routers/api/v1/utils\"\n\t\"code.gitea.io/gitea/services/context\"\n\t\"code.gitea.io/gitea/services/convert\"\n\trelease_service \"code.gitea.io/gitea/services/release\"\n)\n\n// GetRelease get a single release of a repository\nfunc GetRelease(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id} repository repoGetRelease\n\t// ---\n\t// summary: Get a release\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to get\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tid := ctx.PathParamInt64(\"id\")\n\trelease, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || release.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release))\n}\n\n// GetLatestRelease gets the most recent non-prerelease, non-draft release of a repository, sorted by created_at\nfunc GetLatestRelease(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/latest repository repoGetLatestRelease\n\t// ---\n\t// summary: Gets the most recent non-prerelease, non-draft release of a repository, sorted by created_at\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\trelease, err := repo_model.GetLatestReleaseByRepoID(ctx, ctx.Repo.Repository.ID)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) ||\n\t\trelease.IsTag || release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release))\n}\n\n// ListReleases list a repository's releases\nfunc ListReleases(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases repository repoListReleases\n\t// ---\n\t// summary: List a repo's releases\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: draft\n\t//   in: query\n\t//   description: filter (exclude / include) drafts, if you dont have repo write access none will show\n\t//   type: boolean\n\t// - name: pre-release\n\t//   in: query\n\t//   description: filter (exclude / include) pre-releases\n\t//   type: boolean\n\t// - name: page\n\t//   in: query\n\t//   description: page number of results to return (1-based)\n\t//   type: integer\n\t// - name: limit\n\t//   in: query\n\t//   description: page size of results\n\t//   type: integer\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/ReleaseList\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\tlistOptions := utils.GetListOptions(ctx)\n\n\topts := repo_model.FindReleasesOptions{\n\t\tListOptions:   listOptions,\n\t\tIncludeDrafts: ctx.Repo.AccessMode >= perm.AccessModeWrite || ctx.Repo.UnitAccessMode(unit.TypeReleases) >= perm.AccessModeWrite,\n\t\tIncludeTags:   false,\n\t\tIsDraft:       ctx.FormOptionalBool(\"draft\"),\n\t\tIsPreRelease:  ctx.FormOptionalBool(\"pre-release\"),\n\t\tRepoID:        ctx.Repo.Repository.ID,\n\t}\n\n\treleases, err := db.Find[repo_model.Release](ctx, opts)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\trels := make([]*api.Release, len(releases))\n\tfor i, release := range releases {\n\t\tif err := release.LoadAttributes(ctx); err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\trels[i] = convert.ToAPIRelease(ctx, ctx.Repo.Repository, release)\n\t}\n\n\tfilteredCount, err := db.Count[repo_model.Release](ctx, opts)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\tctx.SetLinkHeader(int(filteredCount), listOptions.PageSize)\n\tctx.SetTotalCountHeader(filteredCount)\n\tctx.JSON(http.StatusOK, rels)\n}\n\n// CreateRelease create a release\nfunc CreateRelease(ctx *context.APIContext) {\n\t// swagger:operation POST /repos/{owner}/{repo}/releases repository repoCreateRelease\n\t// ---\n\t// summary: Create a release\n\t// consumes:\n\t// - application/json\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/CreateReleaseOption\"\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"409\":\n\t//     \"$ref\": \"#/responses/error\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\n\tform := web.GetForm(ctx).(*api.CreateReleaseOption)\n\tif ctx.Repo.Repository.IsEmpty {\n\t\tctx.APIError(http.StatusUnprocessableEntity, errors.New(\"repo is empty\"))\n\t\treturn\n\t}\n\trel, err := repo_model.GetRelease(ctx, ctx.Repo.Repository.ID, form.TagName)\n\tif err != nil {\n\t\tif !repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\t// If target is not provided use default branch\n\t\tif len(form.Target) == 0 {\n\t\t\tform.Target = ctx.Repo.Repository.DefaultBranch\n\t\t}\n\t\trel = &repo_model.Release{\n\t\t\tRepoID:       ctx.Repo.Repository.ID,\n\t\t\tPublisherID:  ctx.Doer.ID,\n\t\t\tPublisher:    ctx.Doer,\n\t\t\tTagName:      form.TagName,\n\t\t\tTarget:       form.Target,\n\t\t\tTitle:        form.Title,\n\t\t\tNote:         form.Note,\n\t\t\tIsDraft:      form.IsDraft,\n\t\t\tIsPrerelease: form.IsPrerelease,\n\t\t\tIsTag:        false,\n\t\t\tRepo:         ctx.Repo.Repository,\n\t\t}\n\t\t// GitHub doesn't have \"tag_message\", GitLab has: https://docs.gitlab.com/api/releases/#create-a-release\n\t\t// It doesn't need to be the same as the \"release note\"\n\t\tif err := release_service.CreateRelease(ctx.Repo.GitRepo, rel, nil, form.TagMessage); err != nil {\n\t\t\tif repo_model.IsErrReleaseAlreadyExist(err) {\n\t\t\t\tctx.APIError(http.StatusConflict, err)\n\t\t\t} else if release_service.IsErrProtectedTagName(err) {\n\t\t\t\tctx.APIError(http.StatusUnprocessableEntity, err)\n\t\t\t} else if git.IsErrNotExist(err) {\n\t\t\t\tctx.APIError(http.StatusNotFound, fmt.Errorf(\"target \\\"%v\\\" not found: %w\", rel.Target, err))\n\t\t\t} else {\n\t\t\t\tctx.APIErrorInternal(err)\n\t\t\t}\n\t\t\treturn\n\t\t}\n\t} else {\n\t\tif !rel.IsTag {\n\t\t\tctx.APIError(http.StatusConflict, \"Release is has no Tag\")\n\t\t\treturn\n\t\t}\n\n\t\trel.Title = form.Title\n\t\trel.Note = form.Note\n\t\trel.IsDraft = form.IsDraft\n\t\trel.IsPrerelease = form.IsPrerelease\n\t\trel.PublisherID = ctx.Doer.ID\n\t\trel.IsTag = false\n\t\trel.Repo = ctx.Repo.Repository\n\t\trel.Publisher = ctx.Doer\n\t\trel.Target = form.Target\n\n\t\tif err = release_service.UpdateRelease(ctx, ctx.Doer, ctx.Repo.GitRepo, rel, nil, nil, nil); err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t}\n\tctx.JSON(http.StatusCreated, convert.ToAPIRelease(ctx, ctx.Repo.Repository, rel))\n}\n\n// EditRelease edit a release\nfunc EditRelease(ctx *context.APIContext) {\n\t// swagger:operation PATCH /repos/{owner}/{repo}/releases/{id} repository repoEditRelease\n\t// ---\n\t// summary: Update a release\n\t// consumes:\n\t// - application/json\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to edit\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/EditReleaseOption\"\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tform := web.GetForm(ctx).(*api.EditReleaseOption)\n\tid := ctx.PathParamInt64(\"id\")\n\trel, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || rel.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif len(form.TagName) > 0 {\n\t\trel.TagName = form.TagName\n\t}\n\tif len(form.Target) > 0 {\n\t\trel.Target = form.Target\n\t}\n\tif len(form.Title) > 0 {\n\t\trel.Title = form.Title\n\t}\n\tif len(form.Note) > 0 {\n\t\trel.Note = form.Note\n\t}\n\tif form.IsDraft != nil {\n\t\trel.IsDraft = *form.IsDraft\n\t}\n\tif form.IsPrerelease != nil {\n\t\trel.IsPrerelease = *form.IsPrerelease\n\t}\n\tif err := release_service.UpdateRelease(ctx, ctx.Doer, ctx.Repo.GitRepo, rel, nil, nil, nil); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\t// reload data from database\n\trel, err = repo_model.GetReleaseByID(ctx, id)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err := rel.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, rel))\n}\n\n// DeleteRelease delete a release from a repository\nfunc DeleteRelease(ctx *context.APIContext) {\n\t// swagger:operation DELETE /repos/{owner}/{repo}/releases/{id} repository repoDeleteRelease\n\t// ---\n\t// summary: Delete a release\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to delete\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"204\":\n\t//     \"$ref\": \"#/responses/empty\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\n\tid := ctx.PathParamInt64(\"id\")\n\trel, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || rel.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\tif err := release_service.DeleteReleaseByID(ctx, ctx.Repo.Repository, rel, ctx.Doer, false); err != nil {\n\t\tif release_service.IsErrProtectedTagName(err) {\n\t\t\tctx.APIError(http.StatusUnprocessableEntity, \"user not allowed to delete protected tag\")\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.Status(http.StatusNoContent)\n}\n\n// ===== routers/api/v1/repo/release_attachment.go =====\n// Copyright 2018 The Gitea Authors. All rights reserved.\n// SPDX-License-Identifier: MIT\n\npackage repo\n\n\u0069mport (\n\t\"errors\"\n\t\"net/http\"\n\t\"strings\"\n\n\trepo_model \"code.gitea.io/gitea/models/repo\"\n\t\"code.gitea.io/gitea/modules/log\"\n\t\"code.gitea.io/gitea/modules/setting\"\n\tapi \"code.gitea.io/gitea/modules/structs\"\n\t\"code.gitea.io/gitea/modules/util\"\n\t\"code.gitea.io/gitea/modules/web\"\n\tattachment_service \"code.gitea.io/gitea/services/attachment\"\n\t\"code.gitea.io/gitea/services/context\"\n\t\"code.gitea.io/gitea/services/context/upload\"\n\t\"code.gitea.io/gitea/services/convert\"\n)\n\nfunc checkReleaseMatchRepo(ctx *context.APIContext, releaseID int64) bool {\n\trelease, err := repo_model.GetReleaseByID(ctx, releaseID)\n\tif err != nil {\n\t\tif repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn false\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn false\n\t}\n\tif release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn false\n\t}\n\treturn true\n}\n\n// GetReleaseAttachment gets a single attachment of the release\nfunc GetReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoGetReleaseAttachment\n\t// ---\n\t// summary: Get a release attachment\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to get\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\t// FIXME Should prove the existence of the given repo, but results in unnecessary database requests\n\tctx.JSON(http.StatusOK, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// ListReleaseAttachments lists all attachments of the release\nfunc ListReleaseAttachments(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id}/assets repository repoListReleaseAttachments\n\t// ---\n\t// summary: List release's attachments\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/AttachmentList\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\treleaseID := ctx.PathParamInt64(\"id\")\n\trelease, err := repo_model.GetReleaseByID(ctx, releaseID)\n\tif err != nil {\n\t\tif repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release).Attachments)\n}\n\n// CreateReleaseAttachment creates an attachment and saves the given file\nfunc CreateReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation POST /repos/{owner}/{repo}/releases/{id}/assets repository repoCreateReleaseAttachment\n\t// ---\n\t// summary: Create a release attachment\n\t// produces:\n\t// - application/json\n\t// consumes:\n\t// - multipart/form-data\n\t// - application/octet-stream\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: name\n\t//   in: query\n\t//   description: name of the attachment\n\t//   type: string\n\t//   required: false\n\t// - name: attachment\n\t//   in: formData\n\t//   description: attachment to upload\n\t//   type: file\n\t//   required: false\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"400\":\n\t//     \"$ref\": \"#/responses/error\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"413\":\n\t//     \"$ref\": \"#/responses/error\"\n\n\t// Check if attachments are enabled\n\tif !setting.Attachment.Enabled {\n\t\tctx.APIErrorNotFound(\"Attachment is not enabled\")\n\t\treturn\n\t}\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\t// Get uploaded file from request\n\tvar filename string\n\tvar uploaderFile *attachment_service.UploaderFile\n\tif strings.HasPrefix(strings.ToLower(ctx.Req.Header.Get(\"Content-Type\")), \"multipart/form-data\") {\n\t\tfile, header, err := ctx.Req.FormFile(\"attachment\")\n\t\tif err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\tdefer file.Close()\n\n\t\tfilename = header.Filename\n\t\tif name := ctx.FormString(\"name\"); name != \"\" {\n\t\t\tfilename = name\n\t\t}\n\t\tuploaderFile = attachment_service.NewLimitedUploaderKnownSize(file, header.Size)\n\t} else {\n\t\tfilename = ctx.FormString(\"name\")\n\t\tuploaderFile = attachment_service.NewLimitedUploaderMaxBytesReader(ctx.Req.Body, ctx.Resp)\n\t}\n\n\tif filename == \"\" {\n\t\tctx.APIError(http.StatusBadRequest, \"Could not determine name of attachment.\")\n\t\treturn\n\t}\n\n\t// Create a new attachment and save the file\n\tattach, err := attachment_service.UploadAttachmentReleaseSizeLimit(ctx, uploaderFile, setting.Repository.Release.AllowedTypes, &repo_model.Attachment{\n\t\tName:       filename,\n\t\tUploaderID: ctx.Doer.ID,\n\t\tRepoID:     ctx.Repo.Repository.ID,\n\t\tReleaseID:  releaseID,\n\t})\n\tif err != nil {\n\t\tif upload.IsErrFileTypeForbidden(err) {\n\t\t\tctx.APIError(http.StatusBadRequest, err)\n\t\t\treturn\n\t\t}\n\n\t\tif errors.Is(err, util.ErrContentTooLarge) {\n\t\t\tctx.APIError(http.StatusRequestEntityTooLarge, err)\n\t\t\treturn\n\t\t}\n\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\tctx.JSON(http.StatusCreated, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// EditReleaseAttachment updates the given attachment\nfunc EditReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation PATCH /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoEditReleaseAttachment\n\t// ---\n\t// summary: Edit a release attachment\n\t// produces:\n\t// - application/json\n\t// consumes:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to edit\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/EditAttachmentOptions\"\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tform := web.GetForm(ctx).(*api.EditAttachmentOptions)\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\t// FIXME Should prove the existence of the given repo, but results in unnecessary database requests\n\tif form.Name != \"\" {\n\t\tattach.Name = form.Name\n\t}\n\n\tif err := attachment_service.UpdateAttachment(ctx, setting.Repository.Release.AllowedTypes, attach); err != nil {\n\t\tif upload.IsErrFileTypeForbidden(err) {\n\t\t\tctx.APIError(http.StatusUnprocessableEntity, err)\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusCreated, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// DeleteReleaseAttachment delete a given attachment\nfunc DeleteReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation DELETE /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoDeleteReleaseAttachment\n\t// ---\n\t// summary: Delete a release attachment\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to delete\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"204\":\n\t//     \"$ref\": \"#/responses/empty\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := repo_model.DeleteAttachment(ctx, attach, true); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.Status(http.StatusNoContent)\n}\n\n","after":"// ===== routers/api/v1/repo/release.go =====\n// Copyright 2016 The Gitea Authors. All rights reserved.\n// SPDX-License-Identifier: MIT\n\npackage repo\n\n\u0069mport (\n\t\"errors\"\n\t\"fmt\"\n\t\"net/http\"\n\n\tauth_model \"code.gitea.io/gitea/models/auth\"\n\t\"code.gitea.io/gitea/models/db\"\n\t\"code.gitea.io/gitea/models/perm\"\n\trepo_model \"code.gitea.io/gitea/models/repo\"\n\t\"code.gitea.io/gitea/models/unit\"\n\t\"code.gitea.io/gitea/modules/git\"\n\tapi \"code.gitea.io/gitea/modules/structs\"\n\t\"code.gitea.io/gitea/modules/web\"\n\t\"code.gitea.io/gitea/routers/api/v1/utils\"\n\t\"code.gitea.io/gitea/services/context\"\n\t\"code.gitea.io/gitea/services/convert\"\n\trelease_service \"code.gitea.io/gitea/services/release\"\n)\n\nfunc hasRepoWriteScope(ctx *context.APIContext) bool {\n\tscope, ok := ctx.Data[\"ApiTokenScope\"].(auth_model.AccessTokenScope)\n\tif ctx.Data[\"IsApiToken\"] != true || !ok {\n\t\treturn true\n\t}\n\n\trequiredScopes := auth_model.GetRequiredScopes(auth_model.Write, auth_model.AccessTokenScopeCategoryRepository)\n\tallow, err := scope.HasScope(requiredScopes...)\n\tif err != nil {\n\t\tctx.APIError(http.StatusForbidden, \"checking scope failed: \"+err.Error())\n\t\treturn false\n\t}\n\treturn allow\n}\n\nfunc canAccessDraftRelease(ctx *context.APIContext) bool {\n\tif !ctx.IsSigned || !ctx.Repo.CanWrite(unit.TypeReleases) {\n\t\treturn false\n\t}\n\treturn hasRepoWriteScope(ctx)\n}\n\n// GetRelease get a single release of a repository\nfunc GetRelease(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id} repository repoGetRelease\n\t// ---\n\t// summary: Get a release\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to get\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tid := ctx.PathParamInt64(\"id\")\n\trelease, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || release.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif release.IsDraft { // only the users with write access can see draft releases\n\t\tif !canAccessDraftRelease(ctx) {\n\t\t\tif !ctx.Written() {\n\t\t\t\tctx.APIErrorNotFound()\n\t\t\t}\n\t\t\treturn\n\t\t}\n\t}\n\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release))\n}\n\n// GetLatestRelease gets the most recent non-prerelease, non-draft release of a repository, sorted by created_at\nfunc GetLatestRelease(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/latest repository repoGetLatestRelease\n\t// ---\n\t// summary: Gets the most recent non-prerelease, non-draft release of a repository, sorted by created_at\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\trelease, err := repo_model.GetLatestReleaseByRepoID(ctx, ctx.Repo.Repository.ID)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) ||\n\t\trelease.IsTag || release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release))\n}\n\n// ListReleases list a repository's releases\nfunc ListReleases(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases repository repoListReleases\n\t// ---\n\t// summary: List a repo's releases\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: draft\n\t//   in: query\n\t//   description: filter (exclude / include) drafts, if you dont have repo write access none will show\n\t//   type: boolean\n\t// - name: pre-release\n\t//   in: query\n\t//   description: filter (exclude / include) pre-releases\n\t//   type: boolean\n\t// - name: page\n\t//   in: query\n\t//   description: page number of results to return (1-based)\n\t//   type: integer\n\t// - name: limit\n\t//   in: query\n\t//   description: page size of results\n\t//   type: integer\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/ReleaseList\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\tlistOptions := utils.GetListOptions(ctx)\n\n\tincludeDrafts := (ctx.Repo.AccessMode >= perm.AccessModeWrite || ctx.Repo.UnitAccessMode(unit.TypeReleases) >= perm.AccessModeWrite) && hasRepoWriteScope(ctx)\n\tif ctx.Written() {\n\t\treturn\n\t}\n\topts := repo_model.FindReleasesOptions{\n\t\tListOptions:   listOptions,\n\t\tIncludeDrafts: includeDrafts,\n\t\tIncludeTags:   false,\n\t\tIsDraft:       ctx.FormOptionalBool(\"draft\"),\n\t\tIsPreRelease:  ctx.FormOptionalBool(\"pre-release\"),\n\t\tRepoID:        ctx.Repo.Repository.ID,\n\t}\n\n\treleases, err := db.Find[repo_model.Release](ctx, opts)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\trels := make([]*api.Release, len(releases))\n\tfor i, release := range releases {\n\t\tif err := release.LoadAttributes(ctx); err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\trels[i] = convert.ToAPIRelease(ctx, ctx.Repo.Repository, release)\n\t}\n\n\tfilteredCount, err := db.Count[repo_model.Release](ctx, opts)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\tctx.SetLinkHeader(int(filteredCount), listOptions.PageSize)\n\tctx.SetTotalCountHeader(filteredCount)\n\tctx.JSON(http.StatusOK, rels)\n}\n\n// CreateRelease create a release\nfunc CreateRelease(ctx *context.APIContext) {\n\t// swagger:operation POST /repos/{owner}/{repo}/releases repository repoCreateRelease\n\t// ---\n\t// summary: Create a release\n\t// consumes:\n\t// - application/json\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/CreateReleaseOption\"\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"409\":\n\t//     \"$ref\": \"#/responses/error\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\n\tform := web.GetForm(ctx).(*api.CreateReleaseOption)\n\tif ctx.Repo.Repository.IsEmpty {\n\t\tctx.APIError(http.StatusUnprocessableEntity, errors.New(\"repo is empty\"))\n\t\treturn\n\t}\n\trel, err := repo_model.GetRelease(ctx, ctx.Repo.Repository.ID, form.TagName)\n\tif err != nil {\n\t\tif !repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\t// If target is not provided use default branch\n\t\tif len(form.Target) == 0 {\n\t\t\tform.Target = ctx.Repo.Repository.DefaultBranch\n\t\t}\n\t\trel = &repo_model.Release{\n\t\t\tRepoID:       ctx.Repo.Repository.ID,\n\t\t\tPublisherID:  ctx.Doer.ID,\n\t\t\tPublisher:    ctx.Doer,\n\t\t\tTagName:      form.TagName,\n\t\t\tTarget:       form.Target,\n\t\t\tTitle:        form.Title,\n\t\t\tNote:         form.Note,\n\t\t\tIsDraft:      form.IsDraft,\n\t\t\tIsPrerelease: form.IsPrerelease,\n\t\t\tIsTag:        false,\n\t\t\tRepo:         ctx.Repo.Repository,\n\t\t}\n\t\t// GitHub doesn't have \"tag_message\", GitLab has: https://docs.gitlab.com/api/releases/#create-a-release\n\t\t// It doesn't need to be the same as the \"release note\"\n\t\tif err := release_service.CreateRelease(ctx.Repo.GitRepo, rel, nil, form.TagMessage); err != nil {\n\t\t\tif repo_model.IsErrReleaseAlreadyExist(err) {\n\t\t\t\tctx.APIError(http.StatusConflict, err)\n\t\t\t} else if release_service.IsErrProtectedTagName(err) {\n\t\t\t\tctx.APIError(http.StatusUnprocessableEntity, err)\n\t\t\t} else if git.IsErrNotExist(err) {\n\t\t\t\tctx.APIError(http.StatusNotFound, fmt.Errorf(\"target \\\"%v\\\" not found: %w\", rel.Target, err))\n\t\t\t} else {\n\t\t\t\tctx.APIErrorInternal(err)\n\t\t\t}\n\t\t\treturn\n\t\t}\n\t} else {\n\t\tif !rel.IsTag {\n\t\t\tctx.APIError(http.StatusConflict, \"Release is has no Tag\")\n\t\t\treturn\n\t\t}\n\n\t\trel.Title = form.Title\n\t\trel.Note = form.Note\n\t\trel.IsDraft = form.IsDraft\n\t\trel.IsPrerelease = form.IsPrerelease\n\t\trel.PublisherID = ctx.Doer.ID\n\t\trel.IsTag = false\n\t\trel.Repo = ctx.Repo.Repository\n\t\trel.Publisher = ctx.Doer\n\t\trel.Target = form.Target\n\n\t\tif err = release_service.UpdateRelease(ctx, ctx.Doer, ctx.Repo.GitRepo, rel, nil, nil, nil); err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t}\n\tctx.JSON(http.StatusCreated, convert.ToAPIRelease(ctx, ctx.Repo.Repository, rel))\n}\n\n// EditRelease edit a release\nfunc EditRelease(ctx *context.APIContext) {\n\t// swagger:operation PATCH /repos/{owner}/{repo}/releases/{id} repository repoEditRelease\n\t// ---\n\t// summary: Update a release\n\t// consumes:\n\t// - application/json\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to edit\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/EditReleaseOption\"\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Release\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tform := web.GetForm(ctx).(*api.EditReleaseOption)\n\tid := ctx.PathParamInt64(\"id\")\n\trel, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || rel.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif len(form.TagName) > 0 {\n\t\trel.TagName = form.TagName\n\t}\n\tif len(form.Target) > 0 {\n\t\trel.Target = form.Target\n\t}\n\tif len(form.Title) > 0 {\n\t\trel.Title = form.Title\n\t}\n\tif len(form.Note) > 0 {\n\t\trel.Note = form.Note\n\t}\n\tif form.IsDraft != nil {\n\t\trel.IsDraft = *form.IsDraft\n\t}\n\tif form.IsPrerelease != nil {\n\t\trel.IsPrerelease = *form.IsPrerelease\n\t}\n\tif err := release_service.UpdateRelease(ctx, ctx.Doer, ctx.Repo.GitRepo, rel, nil, nil, nil); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\t// reload data from database\n\trel, err = repo_model.GetReleaseByID(ctx, id)\n\tif err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err := rel.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, rel))\n}\n\n// DeleteRelease delete a release from a repository\nfunc DeleteRelease(ctx *context.APIContext) {\n\t// swagger:operation DELETE /repos/{owner}/{repo}/releases/{id} repository repoDeleteRelease\n\t// ---\n\t// summary: Delete a release\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release to delete\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"204\":\n\t//     \"$ref\": \"#/responses/empty\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\n\tid := ctx.PathParamInt64(\"id\")\n\trel, err := repo_model.GetReleaseForRepoByID(ctx, ctx.Repo.Repository.ID, id)\n\tif err != nil && !repo_model.IsErrReleaseNotExist(err) {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif err != nil && repo_model.IsErrReleaseNotExist(err) || rel.IsTag {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\tif err := release_service.DeleteReleaseByID(ctx, ctx.Repo.Repository, rel, ctx.Doer, false); err != nil {\n\t\tif release_service.IsErrProtectedTagName(err) {\n\t\t\tctx.APIError(http.StatusUnprocessableEntity, \"user not allowed to delete protected tag\")\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.Status(http.StatusNoContent)\n}\n\n// ===== routers/api/v1/repo/release_attachment.go =====\n// Copyright 2018 The Gitea Authors. All rights reserved.\n// SPDX-License-Identifier: MIT\n\npackage repo\n\n\u0069mport (\n\t\"errors\"\n\t\"net/http\"\n\t\"strings\"\n\n\trepo_model \"code.gitea.io/gitea/models/repo\"\n\t\"code.gitea.io/gitea/modules/log\"\n\t\"code.gitea.io/gitea/modules/setting\"\n\tapi \"code.gitea.io/gitea/modules/structs\"\n\t\"code.gitea.io/gitea/modules/util\"\n\t\"code.gitea.io/gitea/modules/web\"\n\tattachment_service \"code.gitea.io/gitea/services/attachment\"\n\t\"code.gitea.io/gitea/services/context\"\n\t\"code.gitea.io/gitea/services/context/upload\"\n\t\"code.gitea.io/gitea/services/convert\"\n)\n\nfunc checkReleaseMatchRepo(ctx *context.APIContext, releaseID int64) bool {\n\trelease, err := repo_model.GetReleaseByID(ctx, releaseID)\n\tif err != nil {\n\t\tif repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn false\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn false\n\t}\n\tif release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn false\n\t}\n\tif release.IsDraft {\n\t\tif !canAccessDraftRelease(ctx) {\n\t\t\tif !ctx.Written() {\n\t\t\t\tctx.APIErrorNotFound()\n\t\t\t}\n\t\t\treturn false\n\t\t}\n\t}\n\treturn true\n}\n\n// GetReleaseAttachment gets a single attachment of the release\nfunc GetReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoGetReleaseAttachment\n\t// ---\n\t// summary: Get a release attachment\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to get\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\t// FIXME Should prove the existence of the given repo, but results in unnecessary database requests\n\tctx.JSON(http.StatusOK, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// ListReleaseAttachments lists all attachments of the release\nfunc ListReleaseAttachments(ctx *context.APIContext) {\n\t// swagger:operation GET /repos/{owner}/{repo}/releases/{id}/assets repository repoListReleaseAttachments\n\t// ---\n\t// summary: List release's attachments\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"200\":\n\t//     \"$ref\": \"#/responses/AttachmentList\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\treleaseID := ctx.PathParamInt64(\"id\")\n\trelease, err := repo_model.GetReleaseByID(ctx, releaseID)\n\tif err != nil {\n\t\tif repo_model.IsErrReleaseNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif release.RepoID != ctx.Repo.Repository.ID {\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\tif release.IsDraft {\n\t\tif !canAccessDraftRelease(ctx) {\n\t\t\tif !ctx.Written() {\n\t\t\t\tctx.APIErrorNotFound()\n\t\t\t}\n\t\t\treturn\n\t\t}\n\t}\n\tif err := release.LoadAttributes(ctx); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusOK, convert.ToAPIRelease(ctx, ctx.Repo.Repository, release).Attachments)\n}\n\n// CreateReleaseAttachment creates an attachment and saves the given file\nfunc CreateReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation POST /repos/{owner}/{repo}/releases/{id}/assets repository repoCreateReleaseAttachment\n\t// ---\n\t// summary: Create a release attachment\n\t// produces:\n\t// - application/json\n\t// consumes:\n\t// - multipart/form-data\n\t// - application/octet-stream\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: name\n\t//   in: query\n\t//   description: name of the attachment\n\t//   type: string\n\t//   required: false\n\t// - name: attachment\n\t//   in: formData\n\t//   description: attachment to upload\n\t//   type: file\n\t//   required: false\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"400\":\n\t//     \"$ref\": \"#/responses/error\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\t//   \"413\":\n\t//     \"$ref\": \"#/responses/error\"\n\n\t// Check if attachments are enabled\n\tif !setting.Attachment.Enabled {\n\t\tctx.APIErrorNotFound(\"Attachment is not enabled\")\n\t\treturn\n\t}\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\t// Get uploaded file from request\n\tvar filename string\n\tvar uploaderFile *attachment_service.UploaderFile\n\tif strings.HasPrefix(strings.ToLower(ctx.Req.Header.Get(\"Content-Type\")), \"multipart/form-data\") {\n\t\tfile, header, err := ctx.Req.FormFile(\"attachment\")\n\t\tif err != nil {\n\t\t\tctx.APIErrorInternal(err)\n\t\t\treturn\n\t\t}\n\t\tdefer file.Close()\n\n\t\tfilename = header.Filename\n\t\tif name := ctx.FormString(\"name\"); name != \"\" {\n\t\t\tfilename = name\n\t\t}\n\t\tuploaderFile = attachment_service.NewLimitedUploaderKnownSize(file, header.Size)\n\t} else {\n\t\tfilename = ctx.FormString(\"name\")\n\t\tuploaderFile = attachment_service.NewLimitedUploaderMaxBytesReader(ctx.Req.Body, ctx.Resp)\n\t}\n\n\tif filename == \"\" {\n\t\tctx.APIError(http.StatusBadRequest, \"Could not determine name of attachment.\")\n\t\treturn\n\t}\n\n\t// Create a new attachment and save the file\n\tattach, err := attachment_service.UploadAttachmentReleaseSizeLimit(ctx, uploaderFile, setting.Repository.Release.AllowedTypes, &repo_model.Attachment{\n\t\tName:       filename,\n\t\tUploaderID: ctx.Doer.ID,\n\t\tRepoID:     ctx.Repo.Repository.ID,\n\t\tReleaseID:  releaseID,\n\t})\n\tif err != nil {\n\t\tif upload.IsErrFileTypeForbidden(err) {\n\t\t\tctx.APIError(http.StatusBadRequest, err)\n\t\t\treturn\n\t\t}\n\n\t\tif errors.Is(err, util.ErrContentTooLarge) {\n\t\t\tctx.APIError(http.StatusRequestEntityTooLarge, err)\n\t\t\treturn\n\t\t}\n\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\n\tctx.JSON(http.StatusCreated, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// EditReleaseAttachment updates the given attachment\nfunc EditReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation PATCH /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoEditReleaseAttachment\n\t// ---\n\t// summary: Edit a release attachment\n\t// produces:\n\t// - application/json\n\t// consumes:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to edit\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: body\n\t//   in: body\n\t//   schema:\n\t//     \"$ref\": \"#/definitions/EditAttachmentOptions\"\n\t// responses:\n\t//   \"201\":\n\t//     \"$ref\": \"#/responses/Attachment\"\n\t//   \"422\":\n\t//     \"$ref\": \"#/responses/validationError\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\tform := web.GetForm(ctx).(*api.EditAttachmentOptions)\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\t// FIXME Should prove the existence of the given repo, but results in unnecessary database requests\n\tif form.Name != \"\" {\n\t\tattach.Name = form.Name\n\t}\n\n\tif err := attachment_service.UpdateAttachment(ctx, setting.Repository.Release.AllowedTypes, attach); err != nil {\n\t\tif upload.IsErrFileTypeForbidden(err) {\n\t\t\tctx.APIError(http.StatusUnprocessableEntity, err)\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.JSON(http.StatusCreated, convert.ToAPIAttachment(ctx.Repo.Repository, attach))\n}\n\n// DeleteReleaseAttachment delete a given attachment\nfunc DeleteReleaseAttachment(ctx *context.APIContext) {\n\t// swagger:operation DELETE /repos/{owner}/{repo}/releases/{id}/assets/{attachment_id} repository repoDeleteReleaseAttachment\n\t// ---\n\t// summary: Delete a release attachment\n\t// produces:\n\t// - application/json\n\t// parameters:\n\t// - name: owner\n\t//   in: path\n\t//   description: owner of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: repo\n\t//   in: path\n\t//   description: name of the repo\n\t//   type: string\n\t//   required: true\n\t// - name: id\n\t//   in: path\n\t//   description: id of the release\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// - name: attachment_id\n\t//   in: path\n\t//   description: id of the attachment to delete\n\t//   type: integer\n\t//   format: int64\n\t//   required: true\n\t// responses:\n\t//   \"204\":\n\t//     \"$ref\": \"#/responses/empty\"\n\t//   \"404\":\n\t//     \"$ref\": \"#/responses/notFound\"\n\n\t// Check if release exists an load release\n\treleaseID := ctx.PathParamInt64(\"id\")\n\tif !checkReleaseMatchRepo(ctx, releaseID) {\n\t\treturn\n\t}\n\n\tattachID := ctx.PathParamInt64(\"attachment_id\")\n\tattach, err := repo_model.GetAttachmentByID(ctx, attachID)\n\tif err != nil {\n\t\tif repo_model.IsErrAttachmentNotExist(err) {\n\t\t\tctx.APIErrorNotFound()\n\t\t\treturn\n\t\t}\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tif attach.ReleaseID != releaseID {\n\t\tlog.Info(\"User requested attachment is not in release, release_id %v, attachment_id: %v\", releaseID, attachID)\n\t\tctx.APIErrorNotFound()\n\t\treturn\n\t}\n\n\tif err := repo_model.DeleteAttachment(ctx, attach, true); err != nil {\n\t\tctx.APIErrorInternal(err)\n\t\treturn\n\t}\n\tctx.Status(http.StatusNoContent)\n}\n\n","diff":"commit 1eced4a7c099459af42412bb32a83241650c0f8f\nAuthor: Lunny Xiao <xiaolunwen@gmail.com>\nDate:   Sun Feb 22 12:56:46 2026 -0800\n\n    Fix get release draft permission check (#36659)\n    \n    Draft release and it's attachments need a write permission to access.\n    \n    ---------\n    \n    Signed-off-by: Lunny Xiao <xiaolunwen@gmail.com>\n    Co-authored-by: Copilot <175728472+Copilot@users.noreply.github.com>\n    Co-authored-by: Giteabot <teabot@gitea.io>\n\ndiff --git a/routers/api/v1/repo/release.go b/routers/api/v1/repo/release.go\nindex 272b395df..4f17590ab 100644\n--- a/routers/api/v1/repo/release.go\n+++ b/routers/api/v1/repo/release.go\n@@ -8,6 +8,7 @@ \u0069mport (\n \t\"fmt\"\n \t\"net/http\"\n \n+\tauth_model \"code.gitea.io/gitea/models/auth\"\n \t\"code.gitea.io/gitea/models/db\"\n \t\"code.gitea.io/gitea/models/perm\"\n \trepo_model \"code.gitea.io/gitea/models/repo\"\n@@ -21,6 +22,28 @@ \u0069mport (\n \trelease_service \"code.gitea.io/gitea/services/release\"\n )\n \n+func hasRepoWriteScope(ctx *context.APIContext) bool {\n+\tscope, ok := ctx.Data[\"ApiTokenScope\"].(auth_model.AccessTokenScope)\n+\tif ctx.Data[\"IsApiToken\"] != true || !ok {\n+\t\treturn true\n+\t}\n+\n+\trequiredScopes := auth_model.GetRequiredScopes(auth_model.Write, auth_model.AccessTokenScopeCategoryRepository)\n+\tallow, err := scope.HasScope(requiredScopes...)\n+\tif err != nil {\n+\t\tctx.APIError(http.StatusForbidden, \"checking scope failed: \"+err.Error())\n+\t\treturn false\n+\t}\n+\treturn allow\n+}\n+\n+func canAccessDraftRelease(ctx *context.APIContext) bool {\n+\tif !ctx.IsSigned || !ctx.Repo.CanWrite(unit.TypeReleases) {\n+\t\treturn false\n+\t}\n+\treturn hasRepoWriteScope(ctx)\n+}\n+\n // GetRelease get a single release of a repository\n func GetRelease(ctx *context.APIContext) {\n \t// swagger:operation GET /repos/{owner}/{repo}/releases/{id} repository repoGetRelease\n@@ -62,6 +85,15 @@ func GetRelease(ctx *context.APIContext) {\n \t\treturn\n \t}\n \n+\tif release.IsDraft { // only the users with write access can see draft releases\n+\t\tif !canAccessDraftRelease(ctx) {\n+\t\t\tif !ctx.Written() {\n+\t\t\t\tctx.APIErrorNotFound()\n+\t\t\t}\n+\t\t\treturn\n+\t\t}\n+\t}\n+\n \tif err := release.LoadAttributes(ctx); err != nil {\n \t\tctx.APIErrorInternal(err)\n \t\treturn\n@@ -151,9 +183,13 @@ func ListReleases(ctx *context.APIContext) {\n \t//     \"$ref\": \"#/responses/notFound\"\n \tlistOptions := utils.GetListOptions(ctx)\n \n+\tincludeDrafts := (ctx.Repo.AccessMode >= perm.AccessModeWrite || ctx.Repo.UnitAccessMode(unit.TypeReleases) >= perm.AccessModeWrite) && hasRepoWriteScope(ctx)\n+\tif ctx.Written() {\n+\t\treturn\n+\t}\n \topts := repo_model.FindReleasesOptions{\n \t\tListOptions:   listOptions,\n-\t\tIncludeDrafts: ctx.Repo.AccessMode >= perm.AccessModeWrite || ctx.Repo.UnitAccessMode(unit.TypeReleases) >= perm.AccessModeWrite,\n+\t\tIncludeDrafts: includeDrafts,\n \t\tIncludeTags:   false,\n \t\tIsDraft:       ctx.FormOptionalBool(\"draft\"),\n \t\tIsPreRelease:  ctx.FormOptionalBool(\"pre-release\"),\ndiff --git a/routers/api/v1/repo/release_attachment.go b/routers/api/v1/repo/release_attachment.go\nindex 33f012523..6b30070db 100644\n--- a/routers/api/v1/repo/release_attachment.go\n+++ b/routers/api/v1/repo/release_attachment.go\n@@ -34,6 +34,14 @@ func checkReleaseMatchRepo(ctx *context.APIContext, releaseID int64) bool {\n \t\tctx.APIErrorNotFound()\n \t\treturn false\n \t}\n+\tif release.IsDraft {\n+\t\tif !canAccessDraftRelease(ctx) {\n+\t\t\tif !ctx.Written() {\n+\t\t\t\tctx.APIErrorNotFound()\n+\t\t\t}\n+\t\t\treturn false\n+\t\t}\n+\t}\n \treturn true\n }\n \n@@ -141,6 +149,14 @@ func ListReleaseAttachments(ctx *context.APIContext) {\n \t\tctx.APIErrorNotFound()\n \t\treturn\n \t}\n+\tif release.IsDraft {\n+\t\tif !canAccessDraftRelease(ctx) {\n+\t\t\tif !ctx.Written() {\n+\t\t\t\tctx.APIErrorNotFound()\n+\t\t\t}\n+\t\t\treturn\n+\t\t}\n+\t}\n \tif err := release.LoadAttributes(ctx); err != nil {\n \t\tctx.APIErrorInternal(err)\n \t\treturn\n"}];
const __SKILL_STRUCT__ = {"skillMd":"---\nname: aegis\ndescription: >\n  Weave security through the whole lifecycle instead of bolting it on at the end,\n  across: risk-based stance and principles (least privilege, defense in depth,\n  fail secure, zero trust), threat model, secure design, input-distrusting code,\n  CI security gates (SAST/DAST/SCA), the OWASP Top 10, and operations — tuned for\n  a world where an agent writes insecure code by\n  default, trusts its input, and ships a vulnerability green. The defensive half\n  of the security pair (the\n  shield); its adversarial counterpart is the `gungnir` skill (the spear). Use\n  when the user wants a system secure-by-design, threat modeling, auth design,\n  secrets management, to prevent injection / XSS / broken access control, set up\n  scanning, meet compliance, or stand up security monitoring. Triggers on \"is this secure\", \"threat model this\", \"secure coding\",\n  \"OWASP\", \"least privilege\", \"manage secrets\", \"auth/authz design\", \"shift-left\n  security / DevSecOps\", \"GDPR / PII / data classification\", \"security review\".\nargument-hint: \"[system / feature / scope to secure]\"\nallowed-tools: Read Bash Edit Write\n---\n\n<!--\nCopyright 2026 IamK77 — Licensed under the Apache License, Version 2.0.\nSee ./LICENSE and ./NOTICE · https://www.apache.org/licenses/LICENSE-2.0\n-->\n\n# aegis\n\n!`checklist init ${CLAUDE_SKILL_DIR} --force`\n\nSecurity is not the last check before launch; it is **a line that runs through every part of the lifecycle.** Treating it as something you add once the features work — *bolt-on security* — fails almost by construction, because the most damaging weaknesses live in architecture and design, where they cannot be patched in afterward, only rebuilt. The correct posture is the one this whole suite keeps returning to: **shift security left** (the DevSecOps idea), the same \"catch it early, surface it cheap\" instinct as quality-left and red-means-stop. This skill is the **shield** — the discipline of building a system secure-by-design — across six gated stages, and it will not advance past a **GATE** until the `checklist` tool clears it. Its adversarial counterpart, the **spear** that attacks what this builds to prove it holds, is the `gungnir` skill.\n\nSecurity is where the agent era is most dangerous, because a vulnerability is the worst possible fit for how an agent works:\n- **The agent writes insecure code by default.** Its training distribution is full of vulnerable patterns — string-concatenated SQL, `eval`, weak or homemade crypto, hard-coded keys — and it reproduces them, because insecure code *works perfectly* until someone attacks it.\n- **A vulnerability passes every green test.** It is the *absence of an attack so far*, not a failure — so it sails through every functional test and every green dashboard, and a green-optimizing agent ships it believing the job is done. Security is the ultimate \"green ≠ correct.\"\n- **The agent has no threat model and trusts its input.** It does not spontaneously ask \"who would attack this, and how\"; it writes the happy path and treats input as friendly, which *is* injection and XSS.\n- **The agent invents crypto/auth and over-grants to make it work.** It will happily generate a custom authentication scheme or widen a permission to `*:*` to clear an error, feeling none of the risk.\n\nSo the rule that governs this skill: **security must be woven in and enforced at every stage, never trusted to instinct** — because the most prolific contributor is an agent whose every default is the insecure one, and whose green light certifies nothing about whether the system can be attacked. The aim is not absolute security (which is impossible and infinitely costly) but **risk management**: identify what is most worth protecting and most likely to be attacked, and concentrate the defense there.\n\n**Discipline:** finish every GATE before the next stage. GATEs are hard — never skip, batch past, or self-certify a stage you have not done. The `checklist` tool enforces the order; let it. Commands address stages by **name**.\n\n**Read [references/agent-era-shifts.md](references/agent-era-shifts.md) first** — it is the heart: what each security practice becomes once the code is written by something with no threat model, no felt risk, and a relentless pull toward whatever turns the light green. If `$ARGUMENTS` is a throwaway with no sensitive data and no exposure, this machinery is overkill — say so. The leanest *sufficient* defense for the system's real risk is the goal, not maximum ceremony.\n\n**Speak the user's language, or the risk gets accepted blind.** This skill makes the user own real trade-offs only they can price: what data is sensitive, what an outage or breach costs, which compliance regime applies, how much defense a risk earns. Read their fluency and gloss a term on first use (threat model, STRIDE, least privilege, defense in depth, SAST/DAST/SCA, CIA, zero trust). A user who signs off on \"this residual risk is acceptable\" in words they never parsed has not accepted it — and the FRAME, MODEL, and OPERATE judgments this skill leans on them for are then hollow.\n\n## The reference library\n\nThe depth lives in `references/`. Open each when a stage sends you there — not all upfront. Eight references back the six stages:\n\n- **[references/decision-tree.md](references/decision-tree.md)** — the engine. Sizing the defense to risk (crown jewels × threat × exposure), the STRIDE threat-model router, the build-vs-buy call for anything security-critical (never invent crypto), the OWASP class → defense map, and the escalation ladder. Open it at the start.\n- [references/agent-era-shifts.md](references/agent-era-shifts.md) — the must-be-told reference: how each security practice changes when an agent writes the code. Load at the start, re-check at every gate.\n- [references/principles-and-stance.md](references/principles-and-stance.md) — the timeless principles (least privilege, defense in depth, fail secure, minimize attack surface, no security through obscurity, zero trust), the CIA triad, crown-jewel / data classification, and security as risk management.\n- [references/threat-modeling.md](references/threat-modeling.md) — STRIDE, trust boundaries, attack-surface enumeration, data-flow diagrams, and ranking by risk — the cheapest, highest-leverage security investment.\n- [references/secure-design.md](references/secure-design.md) — authentication and authorization models, enforcing trust boundaries, layering defense in depth, failing secure, secure defaults, and the never-invent-crypto rule.\n- [references/secure-coding.md](references/secure-coding.md) — never trust input (validate at the boundary), parameterized queries, output encoding, the OWASP Top 10 vulnerability → defense catalog, secrets out of code, and least-privilege wiring.\n- [references/security-testing-and-gates.md](references/security-testing-and-gates.md) — SAST / DAST / SCA / fuzzing automated as blocking CI gates, the OWASP ASVS verification checklist, and the hand-off to the `gungnir` skill for adversarial penetration testing.\n- [references/operate-and-respond.md](references/operate-and-respond.md) — runtime defense, security monitoring and detection, patching and CVE/vulnerability management, secret rotation, and security incident response — because security is never *done*.\n\n---\n\n## STAGE 0 — Frame (set the stance, size the defense to the risk)\n\nSecurity investment must match what is at stake — *够用就好*; a system holding payment data and PII earns threat modeling, hard auth, and security gates, a static brochure site does not. Open **[references/decision-tree.md](references/decision-tree.md)** and **[references/principles-and-stance.md](references/principles-and-stance.md)**: name the **crown jewels** (the data and capabilities most worth protecting — classify what is sensitive/PII/regulated), size the exposure and threat, and set the defense to that. Internalize the **CIA** goal (Confidentiality, Integrity, Availability) and the timeless principles you will apply at every later stage — **least privilege, defense in depth, fail secure, minimize attack surface, no security through obscurity, zero trust** — and the governing fact: **security is risk management, not a quest for the absolute.** Assume the attacker knows your system completely and that any single layer can fail.\n\n**Decide the mode: SETUP or AUDIT.** **SETUP**: build security in from the start as you design and code. **AUDIT / security review** (the common case — an existing system): assess each control capability by capability with evidence (is there a threat model? is input validated? are secrets in a manager? are the gates running?), and fix the gaps — never reporting a control sound because it is *named* rather than *enforced*.\n\n**Name who owns the fix — especially when you operate software you did not author** (an OSS product, a vendored service, a dependency you deploy). Split every gap into two kinds: the ones the **deployment** owns — config, secrets, network exposure, host — which *you* can close, and the ones the **product** owns — its code and architecture — which you can only configure around, upgrade, or report upstream. The most \u0069mportant finding is the one that **survives a correctly-hardened deployment**: it is the product's, no operator can close it, and it is exactly the one a purely adversarial pass buries among the config gaps. The decision tree routes this question (the deployment-vs-product axis) so it is not left to chance. The mirror image, for SETUP of something *others* will deploy: the same axis says make the safe configuration the **default**, because a protection you leave to the operator is one you have not actually shipped.\n\n### GATE — clear before MODEL\n1. `checklist check frame security-stance-set`\n2. `checklist verify frame`\n\n---\n\n## STAGE 1 — Model (think like an attacker, on paper, early)\n\nOpen **[references/threat-modeling.md](references/threat-modeling.md)**. Threat modeling is the single highest-leverage, cheapest security investment, and the thing an agent will never do unasked: systematically ask **\"who would attack this, from where, and what do they want?\"** Use **STRIDE** (Spoofing, Tampering, Repudiation, Information disclosure, Denial of service, Elevation of privilege) over the system's data-flow, mark the **trust boundaries** (where data crosses from less-trusted to more-trusted) and the **attack surface** (every exposed endpoint, port, input, and dependency) right on the architecture diagram, and rank the threats by risk so the defense lands where it matters. This is where the `load-bearing` skill's trust boundaries and the `groundwork` skill's security NFRs become a concrete map of what to defend.\n\n### GATE — clear before DESIGN\n1. `checklist check model threat-model-built`\n2. `checklist verify model`\n\n---\n\n## STAGE 2 — Design (build the defenses into the structure)\n\nOpen **[references/secure-design.md](references/secure-design.md)**. Turn the threat model into design decisions, because the worst weaknesses are architectural and cannot be patched in later:\n\n- **Authentication and authorization, designed not improvised** — use a vetted framework; enforce authorization **server-side on every request**, never by hiding a button.\n- **Enforce the trust boundaries** the model drew, and layer **defense in depth** so no single control is the whole defense — assume each layer can be breached.\n- **Fail secure** — on error, default to *deny*, not allow (an auth service that is down must refuse access, not wave it through).\n- **Minimize the attack surface** — expose the fewest endpoints, ports, and features; turn off and delete what you don't use.\n- **Never invent crypto or core security primitives.** Assume the attacker knows your design (no security through obscurity), so security must hold anyway — which is exactly why you use public, audited algorithms and libraries, never a homemade scheme the agent was happy to generate.\n\n### GATE — clear before BUILD\n1. `checklist check design defenses-and-trust-boundaries`\n2. `checklist verify design`\n\n---\n\n## STAGE 3 — Build (code that never trusts input and never holds a secret)\n\nOpen **[references/secure-coding.md](references/secure-coding.md)**. Secure coding rests on one assumption applied everywhere: **never trust user input** — every external input is validated at the boundary before use.\n\n- **Defend the common vulnerability classes by construction** ([the OWASP Top 10 catalog](references/secure-coding.md)): **parameterized queries / prepared statements** for injection (never concatenate input into SQL or a command), **output encoding** for XSS, **server-side authorization checks** for broken access control, CSRF tokens + `SameSite` cookies, encryption in transit (TLS) and at rest for sensitive data, and safe configuration (no default passwords, no exposed debug endpoints, no public buckets).\n- **Secrets never live in code or logs.** Inject them from a secrets manager / vault (the `flightline` skill blocks them at commit time; this stage keeps them out of the running code and the telemetry — never log a password or PII).\n- **Least privilege in the wiring** — every component, query, and credential gets only the access it needs.\n\n### GATE — clear before VERIFY\n1. `checklist check build input-never-trusted`\n2. `checklist check build secrets-and-least-privilege`\n3. `checklist verify build`\n\n---\n\n## STAGE 4 — Verify (automate the security gates; defend the known classes)\n\nOpen **[references/security-testing-and-gates.md](references/security-testing-and-gates.md)**. Security testing must be automated into the pipeline and run every commit — because a vulnerability is invisible to a functional test and a green-optimizing agent will never seek it out.\n\n- **Gate SAST, DAST, and SCA, blocking** — static analysis of the source, dynamic scanning of the running app, and dependency/supply-chain scanning (the `flightline` skill runs the pipeline; this defines what it must enforce). Add **fuzzing** where input handling is critical. Advisory scans an agent can ignore are not gates.\n- **Walk the OWASP Top 10 as a verification checklist** (OWASP ASVS is the standard form): for each class, confirm the defense exists *and* is tested.\n- **Hand the adversarial half to `gungnir`.** Automated scanning finds *known patterns*; it does not chain small flaws into a real exploit or abuse business logic. That creative, adversarial attack — penetration testing — is the `gungnir` skill's job, and it is where a system is truly proven. Scanning is necessary; it is not sufficient.\n\n### GATE — clear before OPERATE\n1. `checklist check verify security-testing-gated`\n2. `checklist check verify vuln-classes-defended`\n3. `checklist verify verify`\n\n---\n\n## STAGE 5 — Operate (defend, patch, and respond — security is never done)\n\nOpen **[references/operate-and-respond.md](references/operate-and-respond.md)**. New vulnerabilities are disclosed every day and every change can open a new hole, so security is a *continuous* practice, not a one-time checkpoint.\n\n- **Runtime defense and security monitoring** — the security slice of the `stationkeeping` skill's observability: detect and alert on attacks and anomalies, log security events, and keep least-privilege access controls with auditing.\n- **Patch and track vulnerabilities continuously** — follow disclosed CVEs and upgrade vulnerable dependencies promptly (the `husbandry` skill's \"don't drift to EOL,\" in its security form: an unpatched known vulnerability is a standing breach).\n- **Have a security incident-response plan** — a known, rehearsed way to respond to a breach (detect → contain → eradicate → recover → learn), run **blameless** like every incident in this suite so problems surface fast instead of hiding.\n\n### FINAL GATE\n1. `checklist check operate runtime-defense-and-patching`\n2. `checklist check operate incident-response-ready`\n3. `checklist verify operate`\n4. `checklist show` — confirm all six stages passed.\n5. `checklist done` — clear this run's state.\n\n---\n\n## The thread through all of it\n\naegis is the **shield**, and it is cross-cutting by nature: the security line runs through every sibling — security NFRs in `groundwork`, trust boundaries in `load-bearing`, SAST/secret-scan/SCA gates in `flightline`, security testing in `assay`, runtime defense and patching in `stationkeeping` and `husbandry`, and the legible, hard-to-fake signal of `gauge`. aegis owns that line and pulls the threads together; it does not replace the siblings' mechanics, it directs them toward defense. And it is one half of a pair: a shield is only proven against a spear, so what aegis builds, the **`gungnir`** skill attacks — the sharpest spear against the hardest shield. For an agent the lever is the same as everywhere in the suite: every one of its defaults is the insecure one and a vulnerability ships green, so security must be **woven in and gated**, not trusted to an instinct it does not have.\n\n## Anti-patterns (use as a pre-flight checklist)\n\n- **Bolt-on security** — added after the features; the architectural holes can't be patched in. Weave it through from STAGE 0.\n- **Trusting user input** — the root of injection and XSS; validate every external input at the boundary.\n- **Inventing your own crypto / auth** — assume the attacker knows your design; use public, audited primitives.\n- **Security through obscurity** — \"they won't find it\" is not a control; assume full knowledge of the system.\n- **Secrets in code or logs** — inject from a manager; never hard-code a key or log a password/PII.\n- **Over-broad permissions** — the agent widens to `*:*` to stop an error; grant least privilege from deny-all.\n- **Default / unreviewed configuration** — default passwords, debug endpoints, public buckets; secure defaults, reviewed.\n- **Unpatched known vulnerabilities** — a disclosed CVE left in a dependency is a standing breach; patch continuously.\n- **Green ≠ secure** — a vulnerability passes every functional test; gate SAST/DAST/SCA and have `gungnir` attack it.\n- **Chasing absolute security** — impossible and infinitely costly; manage risk — defend the crown jewels first.\n- **Skipping a GATE** — the user's judgment on what to protect and what risk to accept can change the whole plan.\n"};
const __PROFILE__ = {"skill":"engineering/aegis","domain":"application security","reviewSystem":"You are a senior application-security engineer reviewing this server-side Go code for SECURITY vulnerabilities. Identify the security problems and give concrete, specific fixes. Be concise."};

// ============================ app (lifted from index.html) ============================
// claude.ai mode: call the Anthropic API directly with NO key — claude.ai injects
    // authorization. (The original callClaude, inlined so the page is self-contained.)
    async function callClaudeProxy(messages, opts = {}) {
      const body = { model: opts.model || "claude-sonnet-4-6", max_tokens: opts.maxTokens ?? 1500, messages };
      if (opts.system) body.system = opts.system;
      if (opts.temperature != null) body.temperature = opts.temperature;
      const r = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST", headers: { "content-type": "application/json" }, body: JSON.stringify(body),
      });
      const d = await r.json().catch(() => ({}));
      if (!r.ok) throw new Error("Anthropic API " + r.status);
      return (d.content || []).filter((b) => b.type === "text").map((b) => b.text).join("\n");
    }

    // Retry only rate-limit / overload responses (429 / 529 / 503) with exponential backoff + jitter.
    // Other errors (402 balance, 401 auth, parse failures) are NOT retried — they won't fix themselves.
    const isRateLimit = (e) => /(^|\D)(429|529|503)(\D|$)|rate.?limit|overloaded|too many requests/i.test(String((e && e.message) || e));
    async function withRetry(fn, tries = 4, base = 800) {
      for (let i = 0; ; i++) {
        try { return await fn(); }
        catch (e) {
          if (i >= tries - 1 || !isRateLimit(e)) throw e;
          await new Promise((res) => setTimeout(res, base * 2 ** i + Math.random() * base));
        }
      }
    }

    // The manipulated variable: the SAME small review loop (draft → self-revise) runs on BOTH arms;
    // the only difference is whether the skill's guidance is in context.
    const ARMS = {
      base:  { label: "no skill",   blurb: "the small review loop (draft → self-revise), no skill in context" },
      skill: { label: "with skill", blurb: "the same loop, with the skill's guidance in context — the only difference" },
    };
    const ARM_ORDER = ["base", "skill"];
    const clamp = (s) => { const n = Math.round(Number(s)); return Number.isFinite(n) ? Math.max(0, Math.min(10, n)) : 0; };
    const pct = (x) => (x == null ? "—" : Math.round(x * 100) + "%");
    const ls = (k, d) => { try { return localStorage.getItem(k) ?? d; } catch (e) { return d; } };
    const save = (k, v) => { try { localStorage.setItem(k, v); } catch (e) {} };

    function App() {
      const [mode, setMode] = useState(null);           // 'local' | 'claudeai'
      const [skill] = useState(() => {
        try { return new URLSearchParams(location.search).get("skill") || "surface/wellspring"; }
        catch (e) { return "surface/wellspring"; }
      });
      const [skillStruct, setSkillStruct] = useState(null);   // {skillMd, references, checklist} for harness
      const [fixtures, setFixtures] = useState([]);
      const [profile, setProfile] = useState({});

      const [flavor, setFlavor] = useState(() => ls("skilllab.flavor", "openai"));
      const [baseUrl, setBaseUrl] = useState(() => ls("skilllab.baseUrl", "https://api.deepseek.com/v1"));
      const [model, setModel] = useState(() => ls("skilllab.model4", "deepseek-v4-pro"));
      const [apiKey, setApiKey] = useState("");
      const [claudeModel, setClaudeModel] = useState("claude-sonnet-4-6");

      const [arms, setArms] = useState({ base: true, skill: true });
      const [trials, setTrials] = useState(4);
      const concurrency = mode === "claudeai" ? 8 : 12;   // claude.ai rate-limits harder; local can push 12
      const [running, setRunning] = useState(false);
      const [log, setLog] = useState([]);
      const [results, setResults] = useState([]);   // [{fixture, arm, meanFound, fpRate, n, records}]
      const [err, setErr] = useState("");
      const push = (line) => setLog((l) => [...l.slice(-400), line]);

      useEffect(() => { save("skilllab.flavor", flavor); }, [flavor]);
      useEffect(() => { save("skilllab.baseUrl", baseUrl); }, [baseUrl]);
      useEffect(() => { save("skilllab.model4", model); }, [model]);

      useEffect(() => {
        setMode("claudeai");
        setSkillStruct(__SKILL_STRUCT__); setFixtures(__FIXTURES__); setProfile(__PROFILE__);
      }, []);

      const callModel = (role) => (messages, opts) => withRetry(async () => {
        if (mode === "claudeai") return callClaudeProxy(messages, { ...opts, model: claudeModel });
        const provider = { flavor, baseUrl, apiKey, model };
        const r = await fetch("/api/model", {
          method: "POST", headers: { "content-type": "application/json" },
          body: JSON.stringify({ role, messages, opts, provider }),
        });
        const j = await r.json().catch(() => ({}));
        if (!r.ok || j.error) throw new Error(j.error || ("HTTP " + r.status));
        return j.text;
      });

      const providerReady = mode === "claudeai" ? !!claudeModel
        : flavor === "openai" ? !!(baseUrl && model && apiKey) : !!(model && apiKey);
      const selected = ARM_ORDER.filter((a) => arms[a]);
      const skillReady = !arms.skill || !!(skillStruct && skillStruct.skillMd);
      const configReady = providerReady && selected.length >= 1 && skillReady;
      const toggleArm = (a) => setArms((s) => ({ ...s, [a]: !s[a] }));

      async function run() {
        setRunning(true); setErr(""); setResults([]); setLog([]);
        const callReview = callModel("review"), callGrade = callModel("grade");
        const domain = profile.domain || "architecture";
        const system = profile.reviewSystem;
        const units = [];
        for (const fx of fixtures) for (const arm of selected) for (let t = 1; t <= trials; t++) units.push({ fx, arm, t });
        const done = [];
        const recompute = () => {
          const groups = {};
          for (const d of done) (groups[d.fixture + "|" + d.arm] ||= []).push(d.record);
          setResults(Object.entries(groups).map(([k, recs]) => {
            const [fixture, arm] = k.split("|");
            return { fixture, arm, ...core.summarize(recs), records: recs };
          }));
        };
        try {
          await core.mapPool(units, concurrency, async (u) => {
            const tag = `[${u.fx.id}] ${u.arm} · t${u.t}`;
            try {
              // SAME small loop on BOTH arms — the ONLY difference is whether the skill is in context.
              const skillText = u.arm === "skill" ? ((skillStruct && skillStruct.skillMd) || null) : null;
              const mh = await core.runMiniHarness({
                callModel: callReview, code: u.fx.before, skillText, domain, system, maxTokens: 8000,
                onEvent: (e) => push(`${tag} · ${e.phase}`),
              });
              const c = await core.gradeConsensus({ callGrade, code: u.fx.before, diff: u.fx.diff, review: mh.review, domain });
              const harmMajority = c.grades.filter((x) => x.harmful).length > c.grades.length / 2;
              const rec = { trial: u.t, foundScore: c.score, foundWhy: c.grades[0].why, harmful: harmMajority, review: mh.review,
                gradeScores: c.scores, gradeEscalated: c.escalated, turns: mh.turns };
              // false-positive control: SAME loop on the already-fixed code → does it cry wolf?
              const mhFP = await core.runMiniHarness({
                callModel: callReview, code: u.fx.after, skillText, domain, system, maxTokens: 8000,
                onEvent: (e) => push(`${tag} · fp ${e.phase}`),
              });
              const fpg = await core.gradeFalsePositive({ callGrade, diff: u.fx.diff, review: mhFP.review, domain });
              rec.falsePositive = fpg.falsePositive; rec.fpWhy = fpg.why; rec.cleanReview = mhFP.review;
              done.push({ fixture: u.fx.id, arm: u.arm, record: rec });
              recompute();
            } catch (e) {
              push(`${tag} · SKIPPED — ${String(e.message || e)}`);
            }
          });
          push("done.");
        } catch (e) { setErr(String(e.message || e)); }
        setRunning(false);
      }

      // mean score for an arm across all fixtures
      const aggOf = (arm) => {
        const rows = results.filter((r) => r.arm === arm);
        if (!rows.length) return null;
        const meanFound = rows.reduce((a, r) => a + r.meanFound, 0) / rows.length;
        const fpRows = rows.filter((r) => r.fpRate != null);
        const fpRate = fpRows.length ? fpRows.reduce((a, r) => a + r.fpRate, 0) / fpRows.length : null;
        const n = rows.reduce((a, r) => a + r.n, 0);
        return { meanFound, fpRate, n };
      };
      const agg = Object.fromEntries(ARM_ORDER.map((a) => [a, aggOf(a)]));
      // headline comparison: workflow vs no-skill if both present, else whatever pair we have
      const hi = agg.skill ? "skill" : null;
      const lo = agg.base ? "base" : null;
      const delta = hi && lo && agg[hi] && agg[lo] ? agg[hi].meanFound - agg[lo].meanFound : null;
      const haveResults = ARM_ORDER.some((a) => agg[a]);
      const envLabel = mode === "local" ? "this machine" : mode === "claudeai" ? "claude.ai" : "detecting…";
      const envKey = mode === "local" ? "local" : mode === "claudeai" ? "claudeai" : "detecting";

      return (
        <div className="shell">
          {/* ── masthead ── */}
          <header className="masthead">
            <span className="wordmark"><span className="brand-dot" />touchstone</span>
            <span className="badge" data-env={envKey}>{envLabel}</span>
          </header>

          {/* ── hero / the question (the empty-screen focal: persuade with zero data) ── */}
          <section className="section hero">
            <div className="gutter-label"><div className="eyebrow">Controlled experiment</div></div>
            <div className="section-body">
              <h1 className="headline">
                Does <span className="mono">{skill.split("/").pop()}</span> change the review?
              </h1>
              <p className="lead">
                Both arms run the <b>same small review loop</b> — a draft, then a self-revision pass — on the same code,
                same model, same blind grader (it never sees the skill). The <b>one variable</b> is whether the skill's
                guidance is in context. The grader scores the review 0–10, crediting the maintainer's real fix <b>or any
                equal-or-better genuine improvement</b>; the maintainer's diff is the known-good anchor (= 6), not the
                only right answer.
              </p>
            </div>
          </section>

          {/* ── fixtures (the credibility evidence — real before→after commits) ── */}
          {fixtures.length > 0 && (
            <section className="section">
              <div className="gutter-label">
                <div className="eyebrow">Fixtures</div>
                <div className="caption">real before→after commits ({fixtures.length})</div>
              </div>
              <div className="section-body fixtures-list">
                {fixtures.map((f) => (
                  <div className="fixture" key={f.id}>
                    <div>
                      <span className="repo">{f.repo}</span>
                      {f.pr ? <span className="caption"> · <a href={f.pr} target="_blank" rel="noreferrer">source</a></span> : null}
                    </div>
                    <div className="prose">{f.fix_summary}</div>
                    <div className="caption file mono">{f.file}</div>
                  </div>
                ))}
              </div>
            </section>
          )}

          {/* ── provider (mode-driven panel) ── */}
          <section className="section">
            <div className="gutter-label">
              <div className="eyebrow">Provider</div>
              <div className="caption">{mode === "claudeai" ? "claude.ai" : "this machine"}</div>
            </div>
            <div className="section-body">
              {mode == null && <div className="caption">detecting environment…</div>}
              {mode === "local" && (
                <>
                  <div className="field-grid">
                    <label className="field"><span className="field-label">kind</span>
                      <select className="select" value={flavor} disabled={running} onChange={(e) => setFlavor(e.target.value)}>
                        <option value="openai">OpenAI-compatible (DeepSeek / dsv4 / …)</option>
                        <option value="anthropic">Anthropic (your key)</option>
                      </select>
                    </label>
                    {flavor === "openai" && (
                      <label className="field"><span className="field-label">base URL</span>
                        <input className="input" value={baseUrl} disabled={running} placeholder="https://api.deepseek.com/v1"
                          onChange={(e) => setBaseUrl(e.target.value)} />
                      </label>
                    )}
                    <label className="field"><span className="field-label">model</span>
                      <input className="input" value={model} disabled={running} placeholder="deepseek-v4-pro"
                        onChange={(e) => setModel(e.target.value)} />
                    </label>
                    <label className="field"><span className="field-label">API key</span>
                      <input className="input" type="password" value={apiKey} disabled={running} placeholder="sk-…"
                        onChange={(e) => setApiKey(e.target.value)} />
                    </label>
                  </div>
                  <p className="caption">
                    Your key stays on this machine — sent only to your local server (<span className="mono">localhost</span>),
                    which makes the provider call. Browsers can't reach providers like dsv4 directly (CORS). Not saved to disk.
                  </p>
                </>
              )}
              {mode === "claudeai" && (
                <>
                  <div className="field-grid">
                    <label className="field"><span className="field-label">model</span>
                      <select className="select" value={claudeModel} disabled={running} onChange={(e) => setClaudeModel(e.target.value)}>
                        <option value="claude-sonnet-4-6">claude-sonnet-4-6</option>
                        <option value="claude-haiku-4-5-20251001">claude-haiku-4-5 (more headroom)</option>
                        <option value="claude-opus-4-8">claude-opus-4-8 (ceiling risk)</option>
                      </select>
                    </label>
                  </div>
                  <p className="caption">Running in claude.ai — injected credentials, no key needed.</p>
                </>
              )}
            </div>
          </section>

          {/* ── delivery arms ── */}
          <section className="section">
            <div className="gutter-label"><div className="eyebrow">Delivery modes</div><div className="caption">what to compare</div></div>
            <div className="section-body">
              {ARM_ORDER.map((a) => (
                <label className="arm-row" key={a}>
                  <span className="arm-head">
                    <input type="checkbox" checked={arms[a]} disabled={running} onChange={() => toggleArm(a)} />
                    {ARMS[a].label}
                  </span>
                  <span className="arm-blurb">{ARMS[a].blurb}</span>
                </label>
              ))}
              {arms.skill && !skillReady && (
                <div className="warn-inline">
                  the “with skill” arm needs the skill text (SKILL.md) — not available here.
                </div>
              )}
            </div>
          </section>

          {/* ── controls + cost line ── */}
          <section className="section">
            <div className="gutter-label"><div className="eyebrow">Run</div></div>
            <div className="section-body">
              <div className="controls">
                <label className="field" style={{ flex: "0 0 auto" }}><span className="field-label">trials / mode</span>
                  <input className="input" type="number" min={1} max={8} value={trials} disabled={running}
                    style={{ inlineSize: "5rem" }}
                    onChange={(e) => setTrials(Math.max(1, Math.min(8, +e.target.value || 1)))} />
                </label>
                <button className="btn-run" onClick={run} disabled={running || !fixtures.length || !configReady}>
                  {running ? "Running…" : "Run experiment"}
                </button>
              </div>
              <p className="cost-line">
                {mode == null ? "detecting environment…" : mode === "local"
                  ? `${flavor}${model ? " / " + model : ""}${providerReady ? "" : "  — fill the provider above"}`
                  : `claude.ai / ${claudeModel}`}
                {"   ·   "}{fixtures.length} fixture × {selected.length} mode × {trials} = {fixtures.length * selected.length * trials} trials
                {"  "}· each arm: 2-pass loop ×2 (before+after FP) + consensus grading 2–3 calls/trial, ≤{concurrency} at once
              </p>
            </div>
          </section>

          {/* ── error (a designed product moment, not a blank/500) ── */}
          {err && (
            <div className="error-block">
              <div>Error: {err}</div>
              <div className="retry-hint">Check the provider and press <b>Run experiment</b> to try again.</div>
            </div>
          )}

          {/* ── result skeleton (running, before first unit completes — matches loaded geometry) ── */}
          {running && !haveResults && (
            <div className="result-panel">
              <div className="eyebrow">Result</div>
              <div className="delta-row"><div className="skeleton delta-sk" /></div>
              <div className="skeleton bar-sk" /><div className="skeleton bar-sk" />
            </div>
          )}

          {/* ── result (the delta is the focal element) ── */}
          {haveResults && (
            <div className="result-panel">
              <div className="eyebrow">Result · review-quality 0–10 (6 = the maintainer's change)</div>
              {delta != null && (
                <div className="delta-row">
                  <div className="delta" data-sign={delta < 0 ? "neg" : "pos"}>
                    {delta >= 0 ? "+" : "−"}{Math.abs(delta).toFixed(1)}
                  </div>
                  <div className="delta-caption">
                    points <b>{ARMS[hi].label}</b> {delta < 0 ? "loses to" : "adds over"} <b>{ARMS[lo].label}</b><br />
                    <span className="mono">{agg[lo].meanFound.toFixed(1)} → {agg[hi].meanFound.toFixed(1)}</span>
                  </div>
                </div>
              )}
              {ARM_ORDER.filter((a) => agg[a]).map((a) => (
                <div className="arm-score" key={a}>
                  <div className="arm-score-head">
                    <span>{ARMS[a].label}{agg[a].fpRate != null ? <span className="caption">  · false-pos {pct(agg[a].fpRate)}</span> : null}</span>
                    <span className="mono">{agg[a].meanFound.toFixed(2)}/10 <span className="caption">(n={agg[a].n})</span></span>
                  </div>
                  <div className="bar-track"><div className="bar-fill" data-arm={a} style={{ "--fill": agg[a].meanFound / 10 }} /></div>
                </div>
              ))}
              {fixtures.length > 1 && (
                <div className="per-fixture">
                  <div className="caption">per fixture</div>
                  {fixtures.map((f) => {
                    const cells = ARM_ORDER.filter((a) => arms[a]).map((a) => {
                      const r = results.find((x) => x.fixture === f.id && x.arm === a);
                      return r ? `${ARMS[a].label} ${r.meanFound.toFixed(1)}` : null;
                    }).filter(Boolean);
                    return cells.length ? <div className="mono" key={f.id}>{f.id}: {cells.join(" · ")}</div> : null;
                  })}
                </div>
              )}
            </div>
          )}

          {/* ── why · per-trial verdicts ── */}
          {haveResults && (
            <section className="section">
              <div className="gutter-label"><div className="eyebrow">Why</div><div className="caption">grader verdicts · expand to read the review</div></div>
              <div className="section-body">
                {ARM_ORDER.filter((a) => arms[a]).flatMap((a) => results.filter((r) => r.arm === a)).map((r, ri) => (
                  <div className="why-group" key={ri}>
                    <div className="why-group-head">{r.fixture} · {ARMS[r.arm].label}</div>
                    {(r.records || []).map((rec, i) => (
                      <details className="trial" key={i}>
                        <summary>
                          <span className="mono">t{rec.trial}: <b>{rec.foundScore}/10</b></span>
                          {rec.gradeScores ? <span className="caption mono">{"  "}· graded {rec.gradeScores.join("/")}{rec.gradeEscalated ? " →3" : ""}</span> : null}
                          {rec.foundWhy ? <span className="caption"> — {rec.foundWhy}</span> : ""}
                          {("falsePositive" in rec) ? <span className="caption">{` · false-pos ${rec.falsePositive ? "YES" : "no"}${rec.fpWhy ? " — " + rec.fpWhy : ""}`}</span> : ""}
                        </summary>
                        <div className="review-body user-text" dir="auto">
                          {rec.review}{rec.cleanReview ? "\n\n— — — review of the ALREADY-FIXED code — — —\n\n" + rec.cleanReview : ""}
                        </div>
                      </details>
                    ))}
                  </div>
                ))}
              </div>
            </section>
          )}

          {/* ── run log ── */}
          {(running || log.length > 0) && (
            <section className="section">
              <div className="gutter-label"><div className="eyebrow">Run log {running ? "· live" : ""}</div></div>
              <div className="section-body">
                <div className="log user-text" dir="auto">
                  {log.map((l, i) => <div key={i}>{l}</div>)}
                </div>
              </div>
            </section>
          )}

          {/* ── read-honestly footer (first-class persuasion content, not fine print) ── */}
          <div className="footer">
            <b>Read honestly:</b> one fixture is one data point and N is small — a signal, not a proof.
            The grader credits <i>any</i> genuinely-better recommendation, not only the maintainer's exact change (fairer, but more
            subjective). The <span className="mono">workflow</span> arm is a faithful <i>reimplementation</i> of running a
            skill as a gated agent (text-marker tools, deterministic gates) — not literally Claude Code — and it costs ~5–13× the
            calls. Code is not executed: this measures the review's advice, not whether a rewrite compiles.
          </div>
        </div>
      );
    }

export default function Touchstone() {
  return (<><style>{STYLES}</style><App /></>);
}
